import React, { useState } from 'react';
import { generateTrendAnalysis } from '../services/gemini';
import { TrendAnalysis, GuidanceResult } from '../types';
import { SpinnerIcon, LinkIcon, ExclamationTriangleIcon, TrendingUpIcon, WrenchScrewdriverIcon, CheckIcon, BriefcaseIcon, RocketLaunchIcon, SparklesIcon } from './Icons';

const AnalysisResult: React.FC<{ result: TrendAnalysis }> = ({ result }) => {
    const renderContent = (content: string) => {
        const lines = content.split('\n').filter(line => line.trim() !== '');
        const elements: React.ReactNode[] = [];
        let listItems: React.ReactNode[] = [];

        const flushList = () => {
            if (listItems.length > 0) {
                elements.push(<ul key={`ul-${elements.length}`} className="space-y-3 pl-2 mt-4">{listItems}</ul>);
                listItems = [];
            }
        };

        const processLineContent = (text: string) => {
            const parts = text.split(/(\*\*.*?\*\*)/g).filter(part => part);
            return parts.map((part, i) =>
                part.startsWith('**') ? (
                    <strong key={i} className="font-bold text-gray-900 dark:text-white">{part.slice(2, -2)}</strong>
                ) : (
                    part
                )
            );
        };

        lines.forEach((line, index) => {
            line = line.trim();

            if (line.startsWith('* ') || line.startsWith('- ')) {
                const itemContent = line.substring(2);
                listItems.push(
                    <li key={index} className="flex items-start gap-3">
                        <CheckIcon className="h-5 w-5 text-green-500 flex-shrink-0 mt-1" />
                        <span className="text-gray-700 dark:text-gray-300 leading-relaxed">{processLineContent(itemContent)}</span>
                    </li>
                );
                return;
            }

            flushList();

            if (line.startsWith('# ')) {
                elements.push(<h1 key={index} className="text-4xl font-extrabold text-gray-900 dark:text-white mb-4">{line.replace('# ', '')}</h1>);
            } else if (line.startsWith('## ')) {
                const headingText = line.replace('## ', '');
                const emoji = headingText.split(' ')[0];
                const title = headingText.split(' ').slice(1).join(' ');

                let icon: React.ReactNode = <span className="text-2xl">{emoji}</span>;

                if (title.includes('Skills')) {
                    icon = <WrenchScrewdriverIcon className="h-6 w-6 text-purple-600 dark:text-purple-400" />;
                } else if (title.includes('Career')) {
                    icon = <BriefcaseIcon className="h-6 w-6 text-purple-600 dark:text-purple-400" />;
                } else if (title.includes('Prepare')) {
                    icon = <RocketLaunchIcon className="h-6 w-6 text-purple-600 dark:text-purple-400" />;
                }

                elements.push(
                     <div key={index} className="flex items-center gap-4 mt-8 mb-4 border-b-2 border-purple-100 dark:border-slate-700 pb-3">
                        <div className="flex-shrink-0 bg-purple-50 dark:bg-purple-900/30 p-2 rounded-lg">{icon}</div>
                        <h2 className="text-2xl font-bold text-gray-800 dark:text-white">{title}</h2>
                    </div>
                );
            } else {
                 elements.push(
                    <p key={index} className="text-gray-700 dark:text-gray-300 leading-relaxed mb-4 text-lg">
                        {processLineContent(line)}
                    </p>
                );
            }
        });

        flushList();
        return elements;
    };


    return (
        <div className="bg-white dark:bg-slate-800 rounded-xl shadow-lg p-6 sm:p-8 mt-8 animate-fade-in-up border border-gray-100 dark:border-slate-700">
            <article className="prose prose-lg dark:prose-invert max-w-none">
                {renderContent(result.content)}
            </article>
            {result.sources.length > 0 && (
                <div className="mt-10 pt-6 border-t border-gray-200 dark:border-slate-700">
                    <h3 className="text-lg font-semibold text-gray-800 dark:text-white mb-4 flex items-center gap-2">
                        <LinkIcon className="h-5 w-5 text-gray-500 dark:text-gray-400" />
                        <span>AI-Researched Sources</span>
                    </h3>
                    <ul className="space-y-2">
                        {result.sources.map((source, index) => (
                            <li key={index}>
                                <a
                                    href={source.web.uri}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    className="block p-3 bg-gray-50 dark:bg-slate-700/50 hover:bg-purple-50 dark:hover:bg-slate-700 rounded-lg transition-colors group"
                                >
                                    <span className="truncate text-sm font-medium text-purple-700 dark:text-purple-300 group-hover:underline">{source.web.title}</span>
                                    <span className="truncate text-xs text-gray-500 dark:text-gray-400 block mt-1">{source.web.uri}</span>
                                </a>
                            </li>
                        ))}
                    </ul>
                </div>
            )}
        </div>
    );
};

