interface AIIdeaGeneratorProps {
    idea: StartupIdea | null;
    setIdea: React.Dispatch<React.SetStateAction<StartupIdea | null>>;
    businessPlan: BusinessPlan | null;
    setBusinessPlan: React.Dispatch<React.SetStateAction<BusinessPlan | null>>;
    userId: string;
}

const AIIdeaGenerator: React.FC<AIIdeaGeneratorProps> = ({ idea, setIdea, businessPlan, setBusinessPlan, userId }) => {
    const [degree, setDegree] = useState('B.Tech');
    const [interest, setInterest] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState('');

    const [isPlanLoading, setIsPlanLoading] = useState(false);
    const [planError, setPlanError] = useState('');
    const [isPlanModalOpen, setIsPlanModalOpen] = useState(false);


    const handleIdeaSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!interest) {
            setError('Please enter an interest.');
            return;
        }
        setError('');
        setIsLoading(true);
        setIdea(null);
        setBusinessPlan(null); // Clear old plan
        try {
            const result = await generateBusinessIdea(degree, interest);
            setIdea(result);
            await saveUserData(userId, { startupIdea: result });
        } catch (err) {
            const errorMessage = err instanceof Error ? err.message : 'Failed to generate an idea. Please try again.';
            setError(errorMessage);
            console.error(err);
        } finally {
            setIsLoading(false);
        }
    };

    const handleCreatePlan = async () => {
        if (!idea) return;

        setIsPlanLoading(true);
        setPlanError('');
        setBusinessPlan(null);

        try {
            const result = await generateBusinessPlan(idea);
            setBusinessPlan(result);
            setIsPlanModalOpen(true);
            await saveUserData(userId, { businessPlan: result });
        } catch (err) {
            const errorMessage = err instanceof Error ? err.message : 'Failed to generate business plan. Please try again.';
            setPlanError(errorMessage);
        } finally {
            setIsPlanLoading(false);
        }
    };

    return (
        <>
            <div className="bg-white dark:bg-slate-800 rounded-xl shadow-md p-6 sm:p-8 transition-all duration-300 ease-in-out hover:shadow-2xl hover:shadow-purple-200/50 dark:hover:shadow-none border border-gray-100 dark:border-slate-700">
                <div className="flex items-center gap-3 mb-3">
                    <SparklesIcon className="h-6 w-6 text-purple-600 dark:text-purple-400" />
                    <h2 className="text-2xl font-bold text-gray-900 dark:text-white">AI Business Idea Generator</h2>
                </div>
                <p className="text-base text-gray-600 dark:text-gray-400 mb-6">
                    Combine your academic field with a personal interest to spark a unique business idea.
                </p>
                <form onSubmit={handleIdeaSubmit}>
                    <div className="space-y-4">
                        <div>
                            <label htmlFor="degree" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Your Field</label>
                            <select
                                id="degree"
                                value={degree}
                                onChange={(e) => setDegree(e.target.value)}
                                className="w-full rounded-md border-gray-300 dark:border-slate-600 shadow-sm focus:border-purple-500 focus:ring-purple-500 bg-white dark:bg-slate-900 text-gray-900 dark:text-white"
                            >
                                <option>B.Tech</option>
                                <option>B.Com</option>
                                <option>B.A.</option>
                            </select>
                        </div>
                        <div>
                            <label htmlFor="interest" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Your Interest</label>
                            <input
                                type="text"
                                id="interest"
                                value={interest}
                                onChange={(e) => setInterest(e.target.value)}
                                placeholder="e.g., Sustainable fashion, Gaming, Fitness"
                                className="w-full rounded-md border-gray-300 dark:border-slate-600 shadow-sm focus:border-purple-500 focus:ring-purple-500 bg-white dark:bg-slate-900 text-gray-900 dark:text-white dark:placeholder-gray-500"
                            />
                        </div>
                    </div>

                    <button
                        type="submit"
                        disabled={isLoading}
                        className="mt-6 w-full flex justify-center items-center gap-2 bg-purple-600 hover:bg-purple-700 text-white font-bold py-2.5 px-4 rounded-lg shadow-sm transition-colors disabled:bg-purple-300"
                    >
                        {isLoading ? (
                            <>
                                <SpinnerIcon className="animate-spin h-5 w-5" />
                                <span>Brainstorming...</span>
                            </>
                        ) : (
                            <>
                                <SparklesIcon className="h-5 w-5" />
                                <span>Generate Idea</span>
                            </>
                        )}
                    </button>
                </form>

                {error && <p className="mt-4 text-center text-sm text-red-600 dark:text-red-400">{error}</p>}

                {idea && <IdeaResultCard idea={idea} onCreatePlan={handleCreatePlan} isPlanLoading={isPlanLoading} />}
                {planError && !isPlanLoading && <p className="mt-4 text-center text-sm text-red-600 dark:text-red-400">{planError}</p>}
            </div>

            <BusinessPlanModal 
                isOpen={isPlanModalOpen}
                onClose={() => setIsPlanModalOpen(false)}
                plan={businessPlan}
                isLoading={isPlanLoading}
                error={planError}
            />
        </>
    );
};

export default AIIdeaGenerator;

