interface UserProfileProps {
  user: User;
  onSignOut: () => void;
}

const UserProfile: React.FC<UserProfileProps> = ({ user, onSignOut }) => {
  const [isOpen, setIsOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  return (
    <div className="relative" ref={dropdownRef}>
      <button onClick={() => setIsOpen(!isOpen)} className="flex items-center space-x-3 transition-opacity hover:opacity-80">
        <span className="hidden sm:inline font-medium text-gray-700 dark:text-gray-200">{user.displayName}</span>
        <img
          className="h-9 w-9 rounded-full object-cover ring-2 ring-offset-2 ring-purple-500 dark:ring-offset-slate-900"
          src={user.photoURL || `https://avatar.vercel.sh/${user.uid}.png`}
          alt="User avatar"
        />
      </button>

      {isOpen && (
        <div className="absolute right-0 mt-2 w-56 bg-white dark:bg-slate-800 rounded-md shadow-lg py-1 z-50 ring-1 ring-black ring-opacity-5 dark:ring-white/10 origin-top-right animate-in fade-in-0 zoom-in-95">
          <div className="px-4 py-3 border-b dark:border-slate-700">
            <p className="text-sm font-semibold text-gray-800 dark:text-white truncate">{user.displayName}</p>
            <p className="text-xs text-gray-500 dark:text-gray-400 truncate">{user.email}</p>
          </div>
          <button
            onClick={() => {
              setIsOpen(false);
