             {!user.isGuest && !user.emailVerified && (
                <div className="mb-6 bg-yellow-50 dark:bg-yellow-900/20 border-l-4 border-yellow-400 dark:border-yellow-600 p-4 rounded-md shadow-sm animate-fade-in-up">
