                        </div>
                        <h3 className="font-bold text-gray-900 dark:text-white text-lg">Potential Challenges & Risks</h3>
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        {result.risks.map((risk, i) => (
