    const contents = [
        ...history.map(msg => ({ role: msg.role, parts: [{ text: msg.text }] })),
        { role: 'user', parts: [{ text: safeMessage }] }
    ];

    const response = await ai.models.generateContent({
        model,
        contents,
        config: { systemInstruction }
    });

    return response.text;
};

