const ChatInterface: React.FC = () => {
    const [messages, setMessages] = useState<ChatMessage[]>([
        { role: 'model', text: "Hello! I am your focused Skill Mentor. I can help you with course recommendations, project ideas, and career roadmaps. What are you learning today?" }
    ]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    const handleSend = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim() || isLoading) return;

        const userMsg: ChatMessage = { role: 'user', text: input };
        setMessages(prev => [...prev, userMsg]);
        setInput('');
        setIsLoading(true);

        try {
            // Prepare history for context
            const history = messages.map(m => ({ role: m.role as 'user' | 'model', text: m.text }));
            const responseText = await generateSkillMentorResponse(history, userMsg.text);
            setMessages(prev => [...prev, { role: 'model', text: responseText }]);
        } catch (error) {
            setMessages(prev => [...prev, { role: 'model', text: "I'm having trouble connecting right now. Please try again.", isError: true }]);
        } finally {
            setIsLoading(false);
        }
    };

    // Render markdown-like bolding
    const renderText = (text: string) => {
        const parts = text.split(/(\*\*.*?\*\*)/g).filter(part => part);
        return parts.map((part, i) =>
            part.startsWith('**') ? <strong key={i} className="font-bold">{part.slice(2, -2)}</strong> : part
        );
    };

    return (
        <div className="bg-white dark:bg-slate-800 rounded-xl shadow-lg border border-gray-200 dark:border-slate-700 flex flex-col h-[600px]">
            <div className="p-4 border-b border-gray-100 dark:border-slate-700 flex items-center gap-2 bg-gradient-to-r from-purple-50 to-white dark:from-slate-800 dark:to-slate-900 rounded-t-xl">
                <div className="p-2 bg-purple-100 dark:bg-purple-900/30 rounded-lg">
                    <RobotIcon className="h-5 w-5 text-purple-600 dark:text-purple-400" />
                </div>
                <div>
                    <h3 className="font-bold text-gray-900 dark:text-white">Skill Mentor AI</h3>
                    <p className="text-xs text-gray-500 dark:text-gray-400">Strictly focused on your career skills</p>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar bg-gray-50/50 dark:bg-slate-900/50">
                {messages.map((msg, idx) => (
                    <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[80%] rounded-2xl px-4 py-3 text-sm leading-relaxed ${
                            msg.role === 'user' 
                                ? 'bg-purple-600 text-white rounded-br-none' 
                                : `bg-white dark:bg-slate-700 text-gray-700 dark:text-gray-200 rounded-bl-none shadow-sm border border-gray-100 dark:border-slate-600 ${msg.isError ? 'border-red-300 bg-red-50 text-red-800' : ''}`
                        }`}>
                            {renderText(msg.text)}
                        </div>
                    </div>
                ))}
                {isLoading && (
                    <div className="flex justify-start">
                        <div className="bg-white dark:bg-slate-700 rounded-2xl rounded-bl-none px-4 py-3 shadow-sm border border-gray-100 dark:border-slate-600">
                            <div className="flex gap-1.5">
