import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage, WidgetType } from '../types';
import { sendMessageToOmniChat } from '../services/gemini';
import { 
    RobotIcon, SparklesIcon, SpinnerIcon, ChatBubbleLeftRightIcon, 
    UserIcon, MenuIcon 
} from './Icons';
import { 
    CollegeListWidget, RoadmapWidget, MarketInsightWidget, 
    SkillGapWidget, CompetitionsWidget, StartupIdeaWidget 
} from './ChatWidgets';

interface OmniChatProps {
    userId: string;
    userName: string;
    onSignOut: () => void;
    onToggleSidebar?: () => void;
}

const OmniChat: React.FC<OmniChatProps> = ({ userId, userName, onSignOut, onToggleSidebar }) => {
    const [messages, setMessages] = useState<ChatMessage[]>([
        {
            id: 'welcome',
            role: 'model',
            text: `Hi ${userName}! I'm your personal Career AI. \n\nI can help you with:\n- **Finding Colleges** 🎓\n- **Creating Roadmaps** 🗺️\n- **Analyzing Skills** 🛠️\n- **Market Insights** 📈\n- **Startup Ideas** 🚀\n\nWhat's on your mind today?`,
            timestamp: Date.now()
        }
    ]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    const handleSend = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim() || isLoading) return;

        const userText = input.trim();
        const userMsg: ChatMessage = { 
            id: Date.now().toString(), 
            role: 'user', 
            text: userText, 
            timestamp: Date.now() 
        };

        setMessages(prev => [...prev, userMsg]);
        setInput('');
        setIsLoading(true);

        try {
            // Prepare context (last 10 messages)
            const context = messages.slice(-10).map(m => ({ role: m.role, text: m.text }));

            const response = await sendMessageToOmniChat(context, userText);

            setMessages(prev => [...prev, response]);
        } catch (error) {
            console.error("Chat Error:", error);
            setMessages(prev => [...prev, {
                id: Date.now().toString(),
                role: 'model',
                text: "I'm having trouble connecting to my brain right now. Please try again in a moment.",
                isError: true,
                timestamp: Date.now()
            }]);
        } finally {
            setIsLoading(false);
        }
    };

    const renderWidget = (widget: ChatMessage['widget']) => {
        if (!widget) return null;
        switch (widget.type) {
            case 'college_list': return <CollegeListWidget colleges={widget.data} />;
            case 'roadmap': return <RoadmapWidget roadmap={widget.data} />;
            case 'market_insight': return <MarketInsightWidget insight={widget.data} />;
            case 'skill_gap': return <SkillGapWidget analysis={widget.data} />;
            case 'competitions_list': return <CompetitionsWidget competitions={widget.data} />;
            case 'startup_idea': return <StartupIdeaWidget idea={widget.data} />;
            default: return null;
        }
    };

    const formatTime = (ts: number) => {
        return new Date(ts).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    };

    return (
        <div className="flex flex-col h-full bg-gray-50 dark:bg-slate-950 relative">

            {/* Simple Header */}
            <header className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-gray-200 dark:border-slate-800 p-4 sticky top-0 z-20 flex justify-between items-center shadow-sm">
                <div className="flex items-center gap-3">
                    {onToggleSidebar && (
                        <button onClick={onToggleSidebar} className="lg:hidden p-2 -ml-2 text-gray-600 dark:text-gray-300">
                            <MenuIcon className="h-6 w-6" />
                        </button>
                    )}
                    <div className="bg-gradient-to-tr from-purple-600 to-indigo-600 p-2 rounded-lg text-white shadow-lg shadow-purple-500/30">
                        <RobotIcon className="h-6 w-6" />
                    </div>
                    <div>
                        <h1 className="font-bold text-gray-900 dark:text-white text-lg leading-tight">Peekafuture AI</h1>
                        <div className="flex items-center gap-1.5">
                            <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
                            <span className="text-xs text-gray-500 dark:text-gray-400 font-medium">Online • Model 2.5 Pro</span>
                        </div>
                    </div>
                </div>

                <button 
                    onClick={onSignOut}
                    className="text-xs font-semibold text-gray-500 dark:text-gray-400 hover:text-red-500 dark:hover:text-red-400 transition-colors bg-gray-100 dark:bg-slate-800 px-3 py-1.5 rounded-lg"
                >
                    Sign Out
                </button>
            </header>

            {/* Messages Area */}
            <div className="flex-1 overflow-y-auto p-4 sm:p-6 space-y-6 custom-scrollbar">
                {messages.map((msg) => (
                    <div 
                        key={msg.id} 
                        className={`flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'} items-end`}
                    >
                        {/* Avatar */}
                        <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center shadow-sm ${
                            msg.role === 'user' 
                                ? 'bg-gray-200 dark:bg-slate-700' 
                                : 'bg-gradient-to-br from-purple-500 to-indigo-600 text-white'
                        }`}>
                            {msg.role === 'user' ? <UserIcon className="h-5 w-5 text-gray-500 dark:text-gray-300" /> : <SparklesIcon className="h-5 w-5" />}
                        </div>

                        {/* Bubble */}
                        <div className={`flex flex-col max-w-[85%] lg:max-w-[70%] ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                            <div className={`px-5 py-3.5 rounded-2xl shadow-sm text-sm sm:text-base leading-relaxed whitespace-pre-wrap ${
                                msg.role === 'user'
                                    ? 'bg-gray-900 dark:bg-white text-white dark:text-gray-900 rounded-br-none'
                                    : `bg-white dark:bg-slate-800 text-gray-800 dark:text-gray-100 border border-gray-100 dark:border-slate-700 rounded-bl-none ${msg.isError ? 'border-red-300 bg-red-50 dark:bg-red-900/10 text-red-800 dark:text-red-300' : ''}`
                            }`}>
                                {/* React Markdown-ish rendering for bold text */}
                                {msg.text.split(/(\*\*.*?\*\*)/g).map((part, i) => 
                                    part.startsWith('**') ? <strong key={i}>{part.slice(2, -2)}</strong> : part
                                )}
                            </div>

                            {/* Widget Area */}
                            {msg.widget && (
                                <div className="w-full animate-fade-in-up">
                                    {renderWidget(msg.widget)}
                                </div>
                            )}

                            <span className="text-[10px] text-gray-400 mt-1 px-1">
                                {formatTime(msg.timestamp)}
                            </span>
                        </div>
                    </div>
                ))}

                {isLoading && (
                    <div className="flex gap-4 items-end">
                        <div className="w-8 h-8 rounded-full bg-gradient-to-br from-purple-500 to-indigo-600 text-white flex items-center justify-center">
                            <SparklesIcon className="h-5 w-5" />
                        </div>
                        <div className="bg-white dark:bg-slate-800 border border-gray-100 dark:border-slate-700 px-4 py-3 rounded-2xl rounded-bl-none shadow-sm flex items-center gap-2">
                            <div className="w-2 h-2 bg-purple-400 rounded-full animate-bounce"></div>
                            <div className="w-2 h-2 bg-purple-400 rounded-full animate-bounce delay-100"></div>
                            <div className="w-2 h-2 bg-purple-400 rounded-full animate-bounce delay-200"></div>
                        </div>
                    </div>
                )}
                <div ref={messagesEndRef} />
            </div>

            {/* Input Area */}
            <div className="p-4 bg-white dark:bg-slate-900 border-t border-gray-200 dark:border-slate-800">
                <form onSubmit={handleSend} className="max-w-4xl mx-auto relative flex items-center gap-3">
                    <input
                        type="text"
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        placeholder="Ask anything... e.g. 'Find engineering colleges in Mumbai'"
                        className="flex-1 bg-gray-100 dark:bg-slate-800 text-gray-900 dark:text-white placeholder-gray-500 rounded-xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-purple-500 transition-all shadow-inner"
                        disabled={isLoading}
                    />
                    <button
                        type="submit"
                        disabled={!input.trim() || isLoading}
                        className="bg-purple-600 hover:bg-purple-700 text-white p-4 rounded-xl shadow-lg shadow-purple-500/30 disabled:opacity-50 disabled:shadow-none transition-all transform hover:scale-105"
                    >
                        {isLoading ? <SpinnerIcon className="h-5 w-5 animate-spin" /> : <ChatBubbleLeftRightIcon className="h-5 w-5" />}
                    </button>
                </form>
                <p className="text-center text-[10px] text-gray-400 mt-2">
                    AI can make mistakes. Please double-check important info.
                </p>
            </div>
        </div>
    );
};

export default OmniChat;

