const MAX_INPUT_LENGTH = 1000;
const truncateInput = (input: string): string => {
    if (!input) return "";
    return input.length > MAX_INPUT_LENGTH ? input.substring(0, MAX_INPUT_LENGTH) + "...(truncated)" : input;
};

