const parseJsonResponse = <T>(text: string): T => {
    const firstBracket = text.indexOf('{');
    const lastBracket = text.lastIndexOf('}');
    const firstSquare = text.indexOf('[');
    const lastSquare = text.lastIndexOf(']');
    let start = -1;
    let end = -1;
    if (firstBracket !== -1 && lastBracket !== -1) {
        if (firstSquare !== -1 && firstSquare < firstBracket) { start = firstSquare; end = lastSquare; } 
        else { start = firstBracket; end = lastBracket; }
    } else if (firstSquare !== -1 && lastSquare !== -1) { start = firstSquare; end = lastSquare; }

    if (start !== -1 && end !== -1) {
        const jsonString = text.substring(start, end + 1);
        try { return JSON.parse(jsonString) as T; } catch (e) { 
             const cleanText = text.replace(/^```json/, '').replace(/```$/, '').trim();
             return JSON.parse(cleanText) as T;
        }
    }
    try {
        const cleanText = text.replace(/^```json/, '').replace(/```$/, '').trim();
        return JSON.parse(cleanText) as T;
    } catch(e) { throw new Error("Invalid JSON response."); }
};

