export const sendMessageToOmniChat = async (history: {role: string, text: string}[], message: string): Promise<ChatMessage> => {
    const model = 'gemini-2.5-pro'; // Capable of tool use

    // 1. Send Message with Tools
    const chat = ai.chats.create({
        model,
        config: {
            systemInstruction: "You are Peekafuture AI, a helpful career guide for students. You have access to tools to find colleges, make roadmaps, analyze markets, etc. Always use a tool if the user asks for specific data. If the user greets you, just reply nicely. Keep text responses concise.",
            tools: [{ functionDeclarations: toolDefinitions }]
        },
        history: history.map(h => ({ role: h.role, parts: [{ text: h.text }] }))
    });

    const result = await chat.sendMessage({ message });
    const response = result.response;

    const responseMsg: ChatMessage = {
        id: Date.now().toString(),
        role: 'model',
        text: response.text || "I've processed that for you.",
        timestamp: Date.now()
    };

    // 2. Handle Tool Calls
    const functionCalls = response.functionCalls;
    if (functionCalls && functionCalls.length > 0) {
        const call = functionCalls[0];
        const args = call.args;

        try {
            let widgetData = null;
            let widgetType = null;

            if (call.name === 'find_colleges') {
                widgetData = await tools_findColleges(args.query as string);
                widgetType = 'college_list';
            } else if (call.name === 'generate_roadmap') {
                widgetData = await tools_generateRoadmap(args.role as string);
                widgetType = 'roadmap';
            } else if (call.name === 'market_analysis') {
                widgetData = await tools_marketAnalysis(args.role as string);
                widgetType = 'market_insight';
            } else if (call.name === 'find_competitions') {
                // Inline implementation using google search tool directly
                const compPrompt = `Find competitions for ${args.interest}. Return JSON array of Competition objects.`;
                const compRes = await ai.models.generateContent({ model: 'gemini-2.5-flash', contents: compPrompt, config: { tools: [{googleSearch:{}}], responseMimeType: 'application/json'} });
                widgetData = parseJsonResponse<Competition[]>(compRes.text);
                widgetType = 'competitions_list';
            } else if (call.name === 'startup_idea') {
                // Inline implementation
                const ideaPrompt = `Startup idea for ${args.degree || 'Student'} interested in ${args.interest}. Return JSON StartupIdea.`;
                const ideaRes = await ai.models.generateContent({ model: 'gemini-2.5-flash', contents: ideaPrompt, config: { responseMimeType: 'application/json'} });
                widgetData = parseJsonResponse<StartupIdea>(ideaRes.text);
                widgetType = 'startup_idea';
            } else if (call.name === 'skill_gap_check') {
                 const gapPrompt = `Skill gap analysis for ${args.targetRole} with skills ${args.currentSkills}. Return JSON SkillGapAnalysis.`;
                 const gapRes = await ai.models.generateContent({ model: 'gemini-2.5-flash', contents: gapPrompt, config: { responseMimeType: 'application/json'} });
                 widgetData = parseJsonResponse<SkillGapAnalysis>(gapRes.text);
                 widgetType = 'skill_gap';
            }

            if (widgetData && widgetType) {
                responseMsg.widget = { type: widgetType as any, data: widgetData };
                // We add a text confirming the action if the model didn't provide much text
                if (!response.text) {
                    responseMsg.text = `Here is the ${widgetType.replace('_', ' ')} you asked for:`;
                }
            }
        } catch (e) {
            console.error("Tool execution failed", e);
            responseMsg.text += "\n(I tried to generate a visual report but encountered an error. Please try again.)";
        }
    }

    return responseMsg;
};

