// Helper to parse JSON from text that might contain Markdown code blocks
const parseJsonResponse = <T>(text: string): T => {
    const firstBracket = text.indexOf('{');
    const lastBracket = text.lastIndexOf('}');
    const firstSquare = text.indexOf('[');
    const lastSquare = text.lastIndexOf(']');
    let start = -1;
    let end = -1;

    // Determine if object or array comes first/last to handle nested structures correctly
    // Simple heuristic: look for outer boundaries
    if (firstSquare !== -1 && (firstBracket === -1 || firstSquare < firstBracket)) {
        start = firstSquare;
        end = lastSquare;
    } else if (firstBracket !== -1) {
        start = firstBracket;
        end = lastBracket;
    }

    if (start !== -1 && end !== -1) {
        const jsonString = text.substring(start, end + 1);
        try { return JSON.parse(jsonString) as T; } catch (e) {
             // Fallback cleanup if strict extraction fails
             const cleanText = text.replace(/```json/g, '').replace(/```/g, '').trim();
             try { return JSON.parse(cleanText) as T; } catch (e2) { 
                 console.error("JSON parse failed", e2);
                 throw new Error("Invalid JSON response format."); 
             }
        }
    }

    // Fallback if no brackets found (unlikely for valid JSON response)
    const cleanText = text.replace(/```json/g, '').replace(/```/g, '').trim();
    try { return JSON.parse(cleanText) as T; } catch(e) { throw new Error("Invalid JSON response."); }
};

