export const generateTrendAnalysis = async (career: string): Promise<TrendAnalysis> => {
    // Requires grounding for up-to-date trends
    const prompt = `Analyze future trends for the career: ${career} over the next 5-10 years.
    Include key skills, emerging roles, growth outlook, and risks.
    Return JSON format matching TrendAnalysis interface.`;

    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview', // Pro for better reasoning and search integration
        contents: prompt,
        config: { tools: [{ googleSearch: {} }], responseMimeType: 'application/json' }
    });

    // Extract sources from grounding metadata if available (manual extraction needed if not in JSON)
    // However, with responseMimeType=json, the model usually embeds structure.
    // If googleSearch is used, the response might contain groundingMetadata separately.
    // The model should try to put sources in the JSON if prompted, but grounding chunks are separate.
    // We will parse the text for the JSON content.

    const analysis = parseJsonResponse<TrendAnalysis>(response.text);

    // Map grounding chunks to sources if possible, or use what the model provided in JSON 'sources' field if prompted correctly.
    // Ideally, we prompt the model to include 'sources' array in the JSON.
    // If the model actually used the tool, the `groundingMetadata` is on the candidate.
    // For simplicity here, we assume the model puts some sources in the JSON text or we leave it empty if not provided.

    // Let's try to enhance sources from grounding chunks if the JSON is empty on sources
    if ((!analysis.sources || analysis.sources.length === 0) && response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
         analysis.sources = response.candidates[0].groundingMetadata.groundingChunks
            .filter(c => c.web)
            .map(c => ({ web: { uri: c.web!.uri, title: c.web!.title || 'Source' } }));
    }

    return analysis;
};

