        role: 'model',
        text: response.text || "I've processed that for you.",
        timestamp: Date.now()
    };

    // Handle Tool Calls
    const functionCalls = response.functionCalls;
    if (functionCalls && functionCalls.length > 0) {
        const call = functionCalls[0];
        const args = call.args;

        try {
            let widgetData = null;
            let widgetType: any = null;

            if (call.name === 'find_colleges') {
                // Use the search tool to find colleges (simulating DB search via search filter extraction for now)
                // For chat context, we can just return a list based on search.
                const searchRes = await performConversationalSearch(args.query as string);
                // In a real app, we'd query DB with searchRes.filters. 
                // Here we'll just mock it or try to fetch data if we had a direct tool.
                // Fallback: Use gemini to Generate a mock list of colleges matching criteria since we don't have DB access here.
                const prompt = `List 3 real colleges matching: ${args.query}. JSON array of College objects.`;
                const colResponse = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt, config: { responseMimeType: 'application/json' }});
                widgetData = parseJsonResponse<College[]>(colResponse.text);
                widgetType = 'college_list';
            } else if (call.name === 'generate_roadmap') {
                widgetData = await generateRoadmap(args.stream as string || 'General', args.role as string);
                widgetType = 'roadmap';
            } else if (call.name === 'market_analysis') {
                widgetData = await generateMarketInsights(args.role as string);
                widgetType = 'market_insight';
            } else if (call.name === 'find_competitions') {
                widgetData = await findCompetitions(args.interest as string);
                widgetType = 'competitions_list';
            } else if (call.name === 'startup_idea') {
                widgetData = await generateBusinessIdea(args.degree as string || 'Student', args.interest as string);
                widgetType = 'startup_idea';
            } else if (call.name === 'skill_gap_check') {
                 widgetData = await generateSkillGapAnalysis(args.targetRole as string, args.currentSkills as string);
                 widgetType = 'skill_gap';
            }

            if (widgetData && widgetType) {
                responseMsg.widget = { type: widgetType, data: widgetData };
                if (!response.text) {
                    responseMsg.text = `Here is the ${widgetType.replace('_', ' ')} you asked for:`;
                }
            }
        } catch (e) {
            console.error("Tool execution failed", e);
            responseMsg.text += "\n(I encountered an error generating the visual report. Please try again.)";
        }
    }

    return responseMsg;
};
